#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5e3+5,mod=1e9+7;
int c[maxn][maxn],n,m;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=0;i<maxn;i++){
		c[i][0]=1;
		for(int j=1;j<=i;j++){
			c[i][j]=(c[i-1][j]+c[i-1][j-1])%mod;
		}
	}
	cout<<c[n][m];
	return 0;
}
